                <div className="vault-footer-actions">
                  <button className="btn-secondary small-btn">DOWNLOAD_INTEL (PDF)</button>
                  <button className="btn-primary small-btn">INITIATE_UPGRADE</button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

